mapper.select:
SELECT COALESCE(MAX(claimed_count), 0) FROM ( SELECT claims.capacity_date, COUNT(*) AS claimed_count FROM reservation_capacity_claims claims JOIN inventory_reservations r ON r.id = claims.reservation_id WHERE claims.product_id = #{productId} AND claims.capacity_date IN
#{capacityDate}
AND ( (r.status = 'ACTIVE' AND r.expires_at > CURRENT_TIMESTAMP(6)) OR r.status = 'CONSUMED' ) GROUP BY claims.capacity_date ) effective_claims

SELECT claims.reservation_id, claims.capacity_date FROM reservation_capacity_claims claims JOIN inventory_reservations r ON r.id = claims.reservation_id WHERE claims.product_id = #{productId} AND claims.capacity_date IN
#{capacityDate}
AND ( (r.status = 'ACTIVE' AND r.expires_at > CURRENT_TIMESTAMP(6)) OR r.status = 'CONSUMED' ) ORDER BY claims.capacity_date ASC, claims.reservation_id ASC FOR UPDATE
